import{_ as a,o as t,c as i,ag as s}from"./chunks/framework.B45ElpZ1.js";const u=JSON.parse('{"title":"Quick Start","description":"Install tradecli, run first-time setup, and launch the interactive TUI.","frontmatter":{"title":"Quick Start","description":"Install tradecli, run first-time setup, and launch the interactive TUI.","outline":2,"head":[["link",{"rel":"canonical","href":"https://tradecli.in/wiki/getting-started/quick-start"}]]},"headers":[],"relativePath":"getting-started/quick-start.md","filePath":"getting-started/quick-start.md"}'),r={name:"getting-started/quick-start.md"};function o(n,e,l,c,d,h){return t(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h1><p>Install the tradecli stack, run first-time setup, check the local environment, and launch the interactive TUI. This page assumes macOS (Apple Silicon) or Linux (x64). Windows users can grab the <code>.zip</code> from the <a href="https://github.com/TradingSandbox/TradingSandbox/releases" target="_blank" rel="noreferrer">releases page</a>.</p><div class="tip custom-block"><p class="custom-block-title">Time required</p><p><strong>~5 minutes</strong> for a working local install. Broker login can take a few extra minutes the first time a workflow needs account data.</p></div><h2 id="_1-install-via-homebrew" tabindex="-1">1. Install via Homebrew <a class="header-anchor" href="#_1-install-via-homebrew" aria-label="Permalink to &quot;1. Install via Homebrew&quot;">​</a></h2><p>The recommended path on macOS and Linux is the Homebrew tap:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> trust</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tap</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> TradingSandbox/tradecli</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> TradingSandbox/tradecli/tradecli</span></span></code></pre></div><p>That installs the local stack tradecli expects:</p><ul><li><code>tradecli</code> - the interactive TUI and agent runtime</li><li><code>ai-trading-office</code> - local office memory and research state</li><li><code>herdr</code> - the agent desk host used when available</li><li><code>node</code> - required for stdio MCP packages such as TradingView</li></ul><p>Verify the install:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tradecli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># tradecli 0.6.11 (or later)</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">Upgrading</p><p>Run <code>tradecli upgrade</code> to update the Homebrew stack. It upgrades <code>tradecli</code> and <code>ai-trading-office</code>, and restarts the AITradingOffice service if it was already running.</p></div><h2 id="_2-run-first-time-setup" tabindex="-1">2. Run first-time setup <a class="header-anchor" href="#_2-run-first-time-setup" aria-label="Permalink to &quot;2. Run first-time setup&quot;">​</a></h2><p>Run the setup wizard once:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tradecli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup</span></span></code></pre></div><p><code>tradecli setup</code> creates <code>~/.tradecli/config.json</code>, writes safe defaults, configures model credentials, caches MCP packages, and runs the same environment checks used by <code>tradecli doctor</code>.</p><p>For API-key access, you can either enter a key in the wizard or set one before running setup:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ANTHROPIC_API_KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;sk-ant-...&quot;</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tradecli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup</span></span></code></pre></div><p>The wizard supports API keys for Anthropic, OpenAI, Google, Groq, xAI, OpenRouter, Mistral, Cerebras, and Hugging Face. For subscription-based OAuth access such as Claude Pro/Max, ChatGPT, GitHub Copilot, or Google AI, launch <code>tradecli</code>, type <code>/login</code>, then re-run <code>tradecli setup</code>. See <a href="./llm-setup">LLM Setup</a> for the full auth flow.</p><p>Setup also covers the supporting local stack:</p><ul><li>Chrome and the tradecli browser profile</li><li>MCP package cache for TradingView</li><li>MCP-backed broker tool and gateway configuration</li><li>Groww auth status, with an optional fix prompt when auth is missing or expired</li><li>local AITradingOffice API defaults</li></ul><p>Kite does not keep the same persistent token shape as Groww, so Kite login happens interactively the first time a Kite workflow needs it.</p><div class="warning custom-block"><p class="custom-block-title">Do not commit API keys</p><p>Keep API keys in your shell rc file (<code>~/.zshrc</code>, <code>~/.bashrc</code>) or the private tradecli auth store. Never commit keys to a repository. If a key leaks, rotate it immediately with the provider.</p></div><h2 id="_3-run-tradecli-doctor" tabindex="-1">3. Run <code>tradecli doctor</code> <a class="header-anchor" href="#_3-run-tradecli-doctor" aria-label="Permalink to &quot;3. Run `tradecli doctor`&quot;">​</a></h2><p>Confirm the environment before serious work:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tradecli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span></code></pre></div><p>Doctor checks the config directory, product auth, LLM auth, Chrome, browser profile, MCP manifests, MCP source packages, broker gateway, broker auth, ports, network, and installed version.</p><p>If a check fails or warns, run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tradecli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --fix</span></span></code></pre></div><p>It prompts before applying available fixes such as creating missing directories, repairing the browser profile, refreshing MCP packages, or re-acquiring Groww OAuth.</p><h2 id="_4-launch-the-tui" tabindex="-1">4. Launch the TUI <a class="header-anchor" href="#_4-launch-the-tui" aria-label="Permalink to &quot;4. Launch the TUI&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tradecli</span></span></code></pre></div><p>Plain <code>tradecli</code> is the launch surface. On first launch, setup runs automatically if it has not completed yet. After startup, you land in the interactive terminal interface, choose a persona, and start working.</p><p>When Herdr is installed and reachable, tradecli can host the TUI in the agent desk automatically. You do not need a separate Herdr command for the normal path.</p><h2 id="_5-pick-your-first-workflow" tabindex="-1">5. Pick your first workflow <a class="header-anchor" href="#_5-pick-your-first-workflow" aria-label="Permalink to &quot;5. Pick your first workflow&quot;">​</a></h2><p>Choose the workflow that matches what you want to do:</p><ul><li><strong>Learner</strong> - guided lessons, quizzes, and broker-aware practice</li><li><strong>Investor</strong> - fundamentals, valuation, Screener.in, thesis review, and portfolio context</li><li><strong>Trader</strong> - Streak or TradingView Desktop workflows for active trading</li><li><strong>Hedge Fund</strong> - Office Mode with a CEO pane coordinating investor and trader employees</li><li><strong>PMS</strong> - Office Mode for client mandates, model portfolios, overlays, and review workflows</li></ul><p>Start with Learner if you are new to trading. Switch personas later with <code>Ctrl+\\</code> inside the TUI.</p><div class="tip custom-block"><p class="custom-block-title">First prompt ideas</p><ul><li><strong>Learner:</strong> &quot;Start chapter 1&quot;</li><li><strong>Investor:</strong> &quot;Run a quick screen for low-debt large caps with &gt;15% ROCE&quot;</li><li><strong>Trader:</strong> &quot;Open the TradingView Desktop path for RELIANCE&quot;</li><li><strong>Hedge Fund:</strong> &quot;Research HDFC Bank and decide whether it fits the book&quot;</li><li><strong>PMS:</strong> &quot;Draft a model portfolio review workflow&quot;</li></ul></div><h2 id="what-s-next" tabindex="-1">What&#39;s next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s next&quot;">​</a></h2><p>Once you have a working install:</p><ul><li><strong>Broker workflows</strong> -&gt; <a href="./broker-setup">Broker Setup</a> - Groww/Kite first-use behavior and local repair path</li><li><strong>Browser workflows</strong> -&gt; <a href="./browser-setup">Browser Setup</a> - Chrome profile and platform automation</li><li><strong>LLM auth</strong> -&gt; <a href="./llm-setup">LLM Setup</a> - API keys and subscription login paths</li><li><strong>Personas</strong> -&gt; <a href="./../guides/personas">Personas guide</a></li><li><strong>Channels and API</strong> -&gt; <a href="./../guides/channels-api">Beyond the TUI</a></li></ul><div class="danger custom-block"><p class="custom-block-title">Not financial advice</p><p><code>tradecli</code> is an educational and analytical tool. Nothing it outputs constitutes a recommendation to buy, sell, or hold any security. Always verify AI outputs against primary sources before trading real capital.</p></div>',42)])])}const k=a(r,[["render",o]]);export{u as __pageData,k as default};
